from dataclasses import dataclass
from enum import IntEnum


INPUT_MOUSE: int = 0

MOUSEEVENTF_MOVE: int       = 0x0001
MOUSEEVENTF_ABSOLUTE: int   = 0x8000
MOUSEEVENTF_LEFTDOWN: int   = 0x0002
MOUSEEVENTF_LEFTUP: int     = 0x0004
MOUSEEVENTF_RIGHTDOWN: int  = 0x0008
MOUSEEVENTF_RIGHTUP: int    = 0x0010
MOUSEEVENTF_MIDDLEDOWN: int = 0x0020
MOUSEEVENTF_MIDDLEUP: int   = 0x0040
MOUSEEVENTF_VIRTUALDESK: int = 0x4000

MMR_MAGIC: bytes = b"MMR\x01"

class EvtCode(IntEnum):
    MOVE       = 0
    CLICK      = 1
    SCROLL     = 2
    KPRESS     = 3
    KREL       = 4
    LOOP_ABOVE = 5
    MOVE_EX    = 6
    MOVE_REC   = 7


SW_W: int     = 40
SW_H: int     = 20
TRACK_H: int  = 14
TRACK_Y: float = (SW_H - TRACK_H) / 2
KNOB_D: int   = 18
KNOB_Y: float = (SW_H - KNOB_D) / 2
KNOB_OFF: int = 1
KNOB_TRAV: int = SW_W - KNOB_D - KNOB_OFF - 2

TRACK_ON: tuple  = (0x89, 0xDF, 0xFF)
TRACK_OFF: tuple = (0x28, 0x28, 0x28)

SEQ_MIN_H: int = 120


@dataclass(frozen=True)
class _ColorScheme:
    bg_main: str        = "#121212"
    bg_dark: str        = "#0a0a0a"
    fg_primary: str     = "#f0f0f0"
    fg_secondary: str   = "#aaaaaa"
    fg_muted: str       = "#7a7a7a"
    fg_heading: str     = "#89dfff"
    accent_blue: str    = "#89dfff"
    accent_red: str     = "#ff4b69"
    accent_red_stop: str = "#ff5a70"
    accent_orange: str  = "#ffaa32"
    accent_green: str   = "#4ade80"
    accent_discord: str = "#8b9cf4"
    bg_input: str       = "#080808"
    bg_input_focus: str = "#0e0e0e"
    bg_row_sel: str     = "rgba(137,223,255,0.07)"
    bg_row: str         = "rgba(255,255,255,0.03)"


COLOR_SCHEME = _ColorScheme()


@dataclass(frozen=True)
class _FontConfig:
    family: str      = "Arial"
    size_xs: int     = 10
    size_sm: int     = 11
    size_md: int     = 12
    size_lg: int     = 13


